"""Unit tests for LoanRecord class."""import pytestfrom datetime import datetime, timedeltafrom src.models.loan import LoanRecordclass TestLoanRecord:    """Test suite for LoanRecord."""    @pytest.fixture    def sample_loan(self):        """Create a sample active loan."""        return LoanRecord.create_loan(            book_isbn="123-456",            member_id="M001",            checkout_date=datetime(2024, 1, 1)        )    def test_loan_initialization(self, sample_loan):        """Test loan is created with correct attributes."""        assert sample_loan.book_isbn == "123-456"        assert sample_loan.member_id == "M001"        assert sample_loan.checkout_date == datetime(2024, 1, 1)        assert sample_loan.due_date == datetime(2024, 1, 15)  # 14 days default        assert sample_loan.is_active() is True    def test_is_overdue_false_when_not_due(self, sample_loan):        """Test that loan is not overdue before due date."""        check_date = datetime(2024, 1, 10)        assert sample_loan.is_overdue(check_date) is False    def test_is_overdue_true_when_past_due(self, sample_loan):        """Test that loan is overdue after due date."""        check_date = datetime(2024, 1, 20)        assert sample_loan.is_overdue(check_date) is True    def test_is_overdue_false_when_returned(self, sample_loan):        """Test that returned loans are never overdue."""        sample_loan.mark_returned(datetime(2024, 1, 20))        check_date = datetime(2024, 1, 25)        assert sample_loan.is_overdue(check_date) is False    def test_get_days_overdue(self, sample_loan):        """Test days overdue calculation."""        # Not overdue        assert sample_loan.get_days_overdue(datetime(2024, 1, 10)) == 0        # Overdue by 5 days        check_date = datetime(2024, 1, 20)        assert sample_loan.get_days_overdue(check_date) == 5    def test_mark_returned(self, sample_loan):        """Test marking a loan as returned."""        return_date = datetime(2024, 1, 18)        sample_loan.mark_returned(return_date)        assert sample_loan.is_active() is False        assert sample_loan.return_date == return_date